import {
  ChangeDetectionStrategy,
  Component,
  OnInit,
  inject,
  signal,
} from '@angular/core';
import { FormsModule } from '@angular/forms';
import { ApiService, errorMessage } from '../core/api.service';
import { CrmTask } from '../core/models';

@Component({
  selector: 'app-tasks',
  standalone: true,
  imports: [FormsModule],
  templateUrl: './tasks.component.html',
  styleUrl: '../shared/list.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class TasksComponent implements OnInit {
  private readonly api = inject(ApiService);

  loading = signal(true);
  error = signal<string | null>(null);
  saving = signal(false);

  tasks = signal<CrmTask[]>([]);

  title = signal('');
  dueDate = signal('');
  relatedTo = signal('');

  async ngOnInit(): Promise<void> {
    this.loading.set(true);
    try {
      this.tasks.set(await this.api.listTasks());
    } catch (err) {
      this.error.set(errorMessage(err, 'Could not load tasks.'));
    } finally {
      this.loading.set(false);
    }
  }

  /**
   * Completion is toggled locally — the backend exposes task create/list but
   * no update-status procedure, so this is an in-session UI state only.
   */
  toggle(id: string): void {
    this.tasks.update((list) =>
      list.map((t) =>
        t.id === id
          ? { ...t, status: t.status === 'Completed' ? 'Open' : 'Completed' }
          : t,
      ),
    );
  }

  async create(): Promise<void> {
    this.error.set(null);
    if (!this.title().trim() || !this.dueDate()) {
      this.error.set('Title and a due date are required.');
      return;
    }
    this.saving.set(true);
    try {
      const created = await this.api.createTask({
        title: this.title().trim(),
        dueDate: this.dueDate(),
      });
      // `relatedTo` is a UI-only field; preserve the entered value on the row.
      const task = { ...created, relatedTo: this.relatedTo().trim() || 'General' };
      this.tasks.update((list) => [task, ...list]);
      this.title.set('');
      this.dueDate.set('');
      this.relatedTo.set('');
    } catch (err) {
      this.error.set(errorMessage(err, 'Could not create the task.'));
    } finally {
      this.saving.set(false);
    }
  }
}
